.navbar {
  display: flex;
  align-items: center;
  padding-inline: 24px;
  padding-block: 12px;
  background: #1e293b;
}

.logo {
  margin-inline-end: auto;  /* Pushes nav links away in LTR, pulls in RTL */
  font-weight: 700;
  color: white;
  text-decoration: none;
  font-size: 1.25rem;
}

.nav-links {
  display: flex;
  gap: 4px;
}

.nav-links a {
  color: #94a3b8;
  text-decoration: none;
  padding-inline: 12px;
  padding-block: 8px;
  border-radius: 6px;
  transition: background 0.2s;
}

.nav-links a:hover {
  background: #334155;
  color: white;
}

.nav-links .active {
  color: white;
  background: #3b82f6;
}

[dir="rtl"] .nav-links a {
  /* No direction changes needed — margin-inline-end and padding-inline handle it */
}

