solution.css:
.article-layout {
  display: grid;
  grid-template-columns: 220px 1fr 200px;
  gap: 24px;
  padding-inline: 32px;
  margin-inline: auto;
  max-inline-size: 1200px;
}

.sidebar {
  position: sticky;
  inset-block-start: 20px;
  block-size: fit-content;
  padding-inline: 16px;
  padding-block: 20px;
  border-inline-end: 1px solid #e5e7eb;
}

.content {
  padding-inline: 16px;
}

.related {
  padding-inline: 16px;
  padding-block: 20px;
  border-inline-start: 1px solid #e5e7eb;
}

/* For RTL and vertical modes, the grid reorders automatically */
/* and border-inline-start/end swap sides */

@media (max-width: 768px) {
  .article-layout {
    grid-template-columns: 1fr;
  }
  .sidebar, .related {
    border-inline: none;
    border-block: 1px solid #e5e7eb;
  }
}
